INSERT OR IGNORE INTO nasakh_mansukh (entry_order, title_id, naskh_type, mansukh_ref, mansukh_ar, mansukh_id, nasikh_ref, nasikh_ar, nasikh_id, explanation_id, source) VALUES (1, 'Perpindahan Kiblat', 'hukm', 'QS. Al-Baqarah: 115', NULL, '"Milik Allah timur dan barat; ke mana pun kamu menghadap, di sanalah wajah Allah." — pada masa awal, kaum muslimin menghadap ke Baitul Maqdis.', 'QS. Al-Baqarah: 144', 'فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ', '"Maka palingkanlah wajahmu ke arah Masjidil Haram."', 'Hukum menghadap Baitul Maqdis dalam shalat dinasakh (dihapus) dan diganti dengan menghadap Ka''bah di Masjidil Haram. Ini contoh nasakh hukum yang paling masyhur.', 'As-Suyuthi, Al-Itqan fi ''Ulum al-Qur''an');
INSERT OR IGNORE INTO nasakh_mansukh (entry_order, title_id, naskh_type, mansukh_ref, mansukh_ar, mansukh_id, nasikh_ref, nasikh_ar, nasikh_id, explanation_id, source) VALUES (2, 'Masa Iddah Wanita yang Ditinggal Wafat Suami', 'hukm', 'QS. Al-Baqarah: 240', NULL, 'Wasiat nafkah dan tempat tinggal selama satu tahun bagi istri yang ditinggal wafat.', 'QS. Al-Baqarah: 234', 'يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا', '"Hendaklah mereka menahan diri (beriddah) selama empat bulan sepuluh hari."', 'Masa iddah satu tahun dinasakh menjadi empat bulan sepuluh hari. Meski secara tertib mushaf ayat 234 lebih dahulu, ayat 240-lah yang turun lebih awal lalu dihapus.', 'An-Nahhas, An-Nasikh wal-Mansukh');
INSERT OR IGNORE INTO nasakh_mansukh (entry_order, title_id, naskh_type, mansukh_ref, mansukh_ar, mansukh_id, nasikh_ref, nasikh_ar, nasikh_id, explanation_id, source) VALUES (3, 'Kewajiban Puasa: Pilihan menjadi Wajib', 'hukm', 'QS. Al-Baqarah: 184', NULL, 'Pada awalnya orang yang mampu boleh memilih: berpuasa, atau tidak berpuasa dengan membayar fidyah memberi makan orang miskin.', 'QS. Al-Baqarah: 185', 'فَمَنْ شَهِدَ مِنْكُمُ الشَّهْرَ فَلْيَصُمْهُ', '"Maka barang siapa di antara kamu menyaksikan (masuknya) bulan itu, hendaklah ia berpuasa."', 'Kebolehan memilih fidyah bagi yang mampu dinasakh; puasa menjadi wajib bagi setiap muslim yang mampu. Fidyah kini hanya berlaku bagi yang benar-benar tidak sanggup (lansia, sakit menahun).', 'HR. Bukhari 4507; As-Suyuthi, Al-Itqan');
INSERT OR IGNORE INTO nasakh_mansukh (entry_order, title_id, naskh_type, mansukh_ref, mansukh_ar, mansukh_id, nasikh_ref, nasikh_ar, nasikh_id, explanation_id, source) VALUES (4, 'Pengharaman Khamr Secara Bertahap', 'hukm', 'QS. Al-Baqarah: 219 & An-Nisa'': 43', NULL, 'Mula-mula disebut ada manfaat dan dosa besar (2:219), lalu dilarang shalat dalam keadaan mabuk (4:43).', 'QS. Al-Ma''idah: 90-91', 'فَاجْتَنِبُوهُ لَعَلَّكُمْ تُفْلِحُونَ', '"...maka jauhilah (khamr, judi, berhala, dan mengundi nasib) agar kamu beruntung."', 'Pengharaman khamr turun bertahap (tadarruj) untuk menuntun umat. Tahap-tahap awal dinasakh oleh pengharaman total dalam QS. Al-Ma''idah — hikmah pentahapan dalam menetapkan hukum.', 'An-Nahhas; Ibn al-Jawzi, Nawasikh al-Qur''an');
INSERT OR IGNORE INTO nasakh_mansukh (entry_order, title_id, naskh_type, mansukh_ref, mansukh_ar, mansukh_id, nasikh_ref, nasikh_ar, nasikh_id, explanation_id, source) VALUES (5, 'Jumlah Musuh yang Wajib Dihadapi dalam Perang', 'hukm', 'QS. Al-Anfal: 65', NULL, 'Satu mukmin wajib bertahan menghadapi sepuluh orang kafir (perbandingan 1:10).', 'QS. Al-Anfal: 66', 'الْآنَ خَفَّفَ اللَّهُ عَنْكُمْ', '"Sekarang Allah telah meringankan kalian..." — satu mukmin menghadapi dua orang (1:2).', 'Beban perbandingan 1:10 diringankan menjadi 1:2 karena pertimbangan kekuatan. Contoh nasakh untuk memberi keringanan (takhfif).', 'HR. Bukhari 4653');
INSERT OR IGNORE INTO nasakh_mansukh (entry_order, title_id, naskh_type, mansukh_ref, mansukh_ar, mansukh_id, nasikh_ref, nasikh_ar, nasikh_id, explanation_id, source) VALUES (6, 'Wasiat untuk Kerabat, dinasakh Ayat Waris', 'hukm', 'QS. Al-Baqarah: 180', NULL, 'Kewajiban berwasiat harta untuk kedua orang tua dan kerabat.', 'QS. An-Nisa'': 11-12 & hadits', 'لَا وَصِيَّةَ لِوَارِثٍ', '"Tidak ada wasiat bagi ahli waris." (HR. Abu Dawud, Tirmidzi) — bagian mereka telah ditetapkan dalam ayat waris.', 'Kewajiban wasiat kepada ahli waris dinasakh oleh ayat-ayat waris (fara''id) yang menetapkan bagian pasti, dikuatkan sabda Nabi ﷺ ''tidak ada wasiat bagi ahli waris''.', 'HR. Abu Dawud 2870 (hasan); An-Nahhas');
INSERT OR IGNORE INTO nasakh_mansukh (entry_order, title_id, naskh_type, mansukh_ref, mansukh_ar, mansukh_id, nasikh_ref, nasikh_ar, nasikh_id, explanation_id, source) VALUES (7, 'Sedekah Sebelum Berbicara Khusus dengan Nabi ﷺ', 'hukm', 'QS. Al-Mujadilah: 12', NULL, 'Perintah bersedekah lebih dahulu sebelum berbincang khusus (najwa) dengan Rasulullah ﷺ.', 'QS. Al-Mujadilah: 13', 'فَإِذْ لَمْ تَفْعَلُوا وَتَابَ اللَّهُ عَلَيْكُمْ', '"Maka apabila kamu tidak melakukannya dan Allah telah memberi ampun kepadamu, maka dirikanlah shalat..."', 'Kewajiban bersedekah sebelum najwa hanya berlaku sebentar lalu dinasakh pada ayat berikutnya. Konon hanya Ali bin Abi Thalib yang sempat mengamalkannya.', 'HR. Tirmidzi 3300; As-Suyuthi, Al-Itqan');
INSERT OR IGNORE INTO nasakh_mansukh (entry_order, title_id, naskh_type, mansukh_ref, mansukh_ar, mansukh_id, nasikh_ref, nasikh_ar, nasikh_id, explanation_id, source) VALUES (8, 'Hukuman bagi Wanita yang Berzina (Awal)', 'hukm', 'QS. An-Nisa'': 15', NULL, 'Wanita yang berbuat keji dikurung di rumah hingga mati atau Allah memberi jalan lain.', 'QS. An-Nur: 2', 'الزَّانِيَةُ وَالزَّانِي فَاجْلِدُوا كُلَّ وَاحِدٍ مِنْهُمَا مِائَةَ جَلْدَةٍ', '"Pezina perempuan dan pezina laki-laki, deralah masing-masing seratus kali..."', '"Jalan lain" yang dijanjikan pada QS. An-Nisa'': 15 kemudian datang berupa hukum had dalam QS. An-Nur (bagi yang belum menikah) dan rajm bagi yang telah menikah (dari sunnah).', 'HR. Muslim 1690; An-Nahhas');
INSERT OR IGNORE INTO nasakh_mansukh (entry_order, title_id, naskh_type, mansukh_ref, mansukh_ar, mansukh_id, nasikh_ref, nasikh_ar, nasikh_id, explanation_id, source) VALUES (9, 'Ayat Rajm (Naskh Tilawah, Hukum Tetap)', 'tilawah', 'Bacaan ayat rajm', 'الشَّيْخُ وَالشَّيْخَةُ إِذَا زَنَيَا فَارْجُمُوهُمَا الْبَتَّةَ', '"Orang tua laki-laki dan perempuan (yang telah menikah) apabila berzina, maka rajamlah keduanya."', 'Hukumnya tetap berlaku', NULL, 'Lafazh ayat ini tidak lagi termasuk bacaan Al-Qur''an, namun hukum rajam bagi pezina muhshan tetap berlaku dan diamalkan Nabi ﷺ serta para khalifah.', 'Contoh naskh tilawah duna hukm: bacaannya dihapus dari mushaf tetapi hukumnya tetap. Diriwayatkan oleh Umar bin Khaththab.', 'HR. Bukhari 6829, Muslim 1691');
INSERT OR IGNORE INTO nasakh_mansukh (entry_order, title_id, naskh_type, mansukh_ref, mansukh_ar, mansukh_id, nasikh_ref, nasikh_ar, nasikh_id, explanation_id, source) VALUES (10, 'Radha''ah: Sepuluh Susuan menjadi Lima', 'tilawah', 'Bacaan ''sepuluh susuan''', NULL, 'Semula turun bahwa yang mengharamkan (menjadikan mahram) adalah sepuluh kali susuan yang diketahui.', 'Lima susuan', 'خَمْسٌ مَعْلُومَاتٌ', '"...lalu dinasakh menjadi lima susuan yang diketahui."', 'Contoh naskh dalam bilangan susuan yang menjadikan mahram. ''Aisyah menyebut keduanya termasuk yang dahulu dibaca; yang berlaku adalah lima susuan.', 'HR. Muslim 1452');
INSERT OR IGNORE INTO nasakh_mansukh (entry_order, title_id, naskh_type, mansukh_ref, mansukh_ar, mansukh_id, nasikh_ref, nasikh_ar, nasikh_id, explanation_id, source) VALUES (11, 'Kelemahlembutan menjadi Perintah Menegakkan Hak', 'hukm', 'QS. Al-Jatsiyah: 14 (dan sejenisnya)', NULL, 'Perintah memaafkan dan berpaling dari gangguan kaum yang tidak mengharapkan hari-hari Allah, pada fase Makkah/awal Madinah.', 'Ayat-ayat penegakan hukum & jihad', NULL, 'Setelah Islam kuat, sebagian perintah ''berpalinglah/maafkanlah'' terkait sikap terhadap permusuhan digantikan oleh ayat penegakan hak dan pembelaan.', 'Sebagian ulama memasukkan ayat-ayat ''berpaling/maafkanlah'' fase awal ke dalam mansukh oleh ayat penegakan syariat setelah negara Islam berdiri. Termasuk bab yang paling banyak diperdebatkan cakupannya.', 'Ibn al-Jawzi, Nawasikh al-Qur''an (dengan catatan perbedaan ulama)');
